// Static Data - полная версия с отслеживанием прогресса
const message = $input.first().json.message?.text || "";
const chatId = $input.first().json.message?.chat?.id;

// Получаем Static Data
const staticData = $getWorkflowStaticData('global');

// ============ ИНИЦИАЛИЗАЦИЯ ============
if (!staticData.state) {
  staticData.state = "start"; // start, waiting_topic, plan_ready, learning, completed
  staticData.learningPlan = [];
  staticData.allConcepts = []; // Все понятия из плана
  staticData.usedConcepts = []; // Уже использованные понятия
  staticData.currentConceptIndex = 0;
  staticData.userTopic = "";
  staticData.userLevel = "новичок";
  staticData.lastUserMessage = "";
  staticData.planCreated = false;
}

// Сохраняем последнее сообщение пользователя
staticData.lastUserMessage = message;

console.log(`📝 Сообщение: "${message}"`);
console.log(`🔧 Состояние: ${staticData.state}`);
console.log(`📌 Использовано понятий: ${staticData.usedConcepts?.length || 0}`);

// ============ ЛОГИКА СОСТОЯНИЙ ============
if (staticData.state === "start" && /привет|hello|hi|старт/i.test(message.toLowerCase())) {
  staticData.state = "waiting_topic";
  console.log("🔄 Переход: start → waiting_topic");
} 
else if (staticData.state === "waiting_topic" && message.length > 10) {
  // Пользователь указал тему
  staticData.userTopic = message;

  // Определяем уровень
  if (message.toLowerCase().includes("новичок")) staticData.userLevel = "новичок";
  else if (message.toLowerCase().includes("средний")) staticData.userLevel = "средний";
  else if (message.toLowerCase().includes("продвинут")) staticData.userLevel = "продвинутый";

  staticData.state = "topic_received";
  console.log(`🔄 Переход: waiting_topic → topic_received (уровень: ${staticData.userLevel})`);
}
else if (staticData.state === "plan_ready") {
  // Проверяем подтверждение плана
  const confirmationWords = ['да', 'ок', 'хорошо', 'начинаем', 'готов', 'yes', 'ok', 'супер'];
  const isConfirmation = confirmationWords.some(word => 
    message.toLowerCase().includes(word)
  );

  if (isConfirmation) {
    staticData.state = "learning";
    console.log("✅ Пользователь подтвердил план! Переход: plan_ready → learning");
  }
}
else if (staticData.state === "learning" && message.includes("?")) {
  // Пользователь задает вопрос - сохраняем тему вопроса
  const question = message.toLowerCase();

  if (question.includes("тип") || question.includes("данн")) {
    staticData.lastQuestionTopic = "типы данных";
  } else if (question.includes("оператор")) {
    staticData.lastQuestionTopic = "операторы";
  } else if (question.includes("функц")) {
    staticData.lastQuestionTopic = "функции";
  } else if (question.includes("объект")) {
    staticData.lastQuestionTopic = "объекты";
  } else if (question.includes("дом")) {
    staticData.lastQuestionTopic = "DOM";
  } else {
    staticData.lastQuestionTopic = "JavaScript";
  }

  console.log(`❓ Задан вопрос по теме: ${staticData.lastQuestionTopic}`);
}

// ============ ВОЗВРАЩАЕМ ДАННЫЕ ============
return [{
  json: {
    chatInput: message, // Просто передаем сообщение
    message: { text: message },
    chatId: chatId,
    staticData: staticData,
    currentState: staticData.state
  }
}];

// УЛЬТРА-ПРОСТОЙ РАБОЧИЙ КОД
const item = $input.first();
const chatId = $('Telegram Trigger').item.json.message.chat.id;

// 1. Берем текст
let text = item.json.TelegramText || item.json.output || "Пост";

// 2. ЗАМЕНЯЕМ ВСЕ спецсимволы на ПРОБЕЛЫ (включая дефис)
text = text.replace(/[-{}()<>\[\]#*_`~\\=+!.]/g, ' ');

// 3. Убираем все ссылки
text = text.replace(/https?:\/\/\S+/g, 'ссылка ');

// 4. Убираем лишние пробелы
text = text.replace(/\s+/g, ' ').trim();

// 5. Берем первые 4000 символов
text = text.substring(0, 4000);

// 6. Если мало текста
if (text.length < 50) {
  text = "Образовательный материал по JavaScript подготовлен на основе информации из интернета.";
}

return [{
  json: {
    TelegramText: text,
    chatId: chatId
  }
}];

// Получаем ответ AI
const data = $input.first().json;
const aiResponse = data.output || data.message?.content || "";

console.log("🤖 AI ответил:", aiResponse.substring(0, 200));

// Получаем Static Data
const staticData = $getWorkflowStaticData('global');

//ПАРСИМ ПЛАН ОБУЧЕНИЯ
if (aiResponse.includes("ПЛАН_ОБУЧЕНИЯ:")) {
  console.log("🎯 План создан");

  // Обновляем состояние
  staticData.state = "plan_ready";
  staticData.planCreated = true;

  // Парсим все понятия из плана
  const lines = aiResponse.split('\n');
  const allConcepts = [];

  for (const line of lines) {
    const trimmed = line.trim();

    // Ищем строки с понятиями в квадратных скобках
    if (trimmed.includes('[') && trimmed.includes(']')) {
      const match = trimmed.match(/\[([^\]]+)\]/);
      if (match) {
        const concepts = match[1].split(',').map(c => c.trim()).filter(c => c.length > 0);
        allConcepts.push(...concepts);
        console.log(`📌 Найдены понятия: ${concepts.join(', ')}`);
      }
    }
  }

  // Сохраняем все понятия
  if (allConcepts.length > 0) {
    staticData.allConcepts = allConcepts;
    staticData.usedConcepts = []; // Сбрасываем использованные
    staticData.currentConceptIndex = 0;

    console.log(`✅ Сохранено ${allConcepts.length} понятий:`, allConcepts);
  }

  // Возвращаем план пользователю
  return [{
    json: {
      hasTavilyFormat: false,
      requiresSearch: "false",
      output: aiResponse
    }
  }];
}

//ПРОВЕРЯЕМ TAVILY ЗАПРОС
const tavilyRegex = /tavily\(query="([^"]+)"\)/;
const match = aiResponse.match(tavilyRegex);

if (match) {
  console.log("✅ Найден tavily запрос:", match[1]);
  return [{
    json: {
      hasTavilyFormat: true,
      requiresSearch: "true",
      query: match[1]
    }
  }];
}

//ОБРАБОТКА "ДА" ПОСЛЕ ПЛАНА
const lastMessage = staticData.lastUserMessage || "";

if (lastMessage.toLowerCase().includes("да") && staticData.state === "plan_ready") {
  console.log("✅ Пользователь подтвердил план");

  // Находим следующее неиспользованное понятие
  let nextConcept = "";

  if (staticData.allConcepts && staticData.allConcepts.length > 0) {
    // Ищем первое неиспользованное понятие
    for (let i = 0; i < staticData.allConcepts.length; i++) {
      const concept = staticData.allConcepts[i];
      if (!staticData.usedConcepts.includes(concept)) {
        nextConcept = concept;
        staticData.currentConceptIndex = i;
        break;
      }
    }

    // Если все использованы, начинаем сначала
    if (!nextConcept && staticData.allConcepts.length > 0) {
      nextConcept = staticData.allConcepts[0];
      staticData.usedConcepts = [];
      staticData.currentConceptIndex = 0;
    }

    // Отмечаем как использованное
    if (nextConcept) {
      if (!staticData.usedConcepts) staticData.usedConcepts = [];
      staticData.usedConcepts.push(nextConcept);
      console.log(`📝 Понятие "${nextConcept}" отмечено как использованное`);
      console.log(`📊 Прогресс: ${staticData.usedConcepts.length}/${staticData.allConcepts.length}`);
    }
  }

  // Если не нашли понятие, используем дефолтное
  if (!nextConcept) {
    nextConcept = "переменные в JavaScript";
  }

  // Создаем поисковый запрос
  const searchQuery = `${nextConcept} объяснение для ${staticData.userLevel} уровня`;
  console.log(`🔍 Создаю запрос: ${searchQuery}`);

  // Меняем состояние
  staticData.state = "learning";

  return [{
    json: {
      hasTavilyFormat: true,
      requiresSearch: "true",
      query: searchQuery,
      currentConcept: nextConcept
    }
  }];
}

//ОБРАБОТКА ВОПРОСОВ ПОЛЬЗОВАТЕЛЯ
// Проверяем, является ли сообщение вопросом
const isQuestion = lastMessage.includes("?") || 
                   /что|как|объясни|расскажи|про/i.test(lastMessage);

if (isQuestion && staticData.state === "learning") {
  console.log("❓ Пользователь задал вопрос:", lastMessage);

  // Определяем тему вопроса
  let topic = "";
  const question = lastMessage.toLowerCase();

  if (question.includes("тип") || question.includes("данн")) {
    topic = "типы данных в JavaScript";
  } else if (question.includes("оператор")) {
    topic = "операторы в JavaScript";
  } else if (question.includes("функц")) {
    topic = "функции в JavaScript";
  } else if (question.includes("объект")) {
    topic = "объекты в JavaScript";
  } else if (question.includes("дом")) {
    topic = "DOM в JavaScript";
  } else if (staticData.lastQuestionTopic) {
    topic = `${staticData.lastQuestionTopic} в JavaScript`;
  } else {
    topic = "JavaScript";
  }

  //Создаем поисковый запрос
  const searchQuery = `${topic} объяснение для ${staticData.userLevel} уровня`;
  console.log(`🔍 Создаю запрос на вопрос: ${searchQuery}`);

  return [{
    json: {
      hasTavilyFormat: true,
      requiresSearch: "true",
      query: searchQuery
    }
  }];
}

//ПРОВЕРЯЕМ ЗАВЕРШЕНИЕ ОБУЧЕНИЯ
if (staticData.allConcepts && staticData.usedConcepts && 
    staticData.allConcepts.length > 0 && 
    staticData.usedConcepts.length >= staticData.allConcepts.length) {

  console.log("🎉 Все понятия изучены!");
  staticData.state = "completed";

  return [{
    json: {
      hasTavilyFormat: false,
      requiresSearch: "false",
      output: "🎉 Поздравляю! Вы изучили все понятия плана! Что хотите изучить дальше?"
    }
  }];
}

//ОБЫЧНЫЙ ОТВЕТ
console.log("📤 Отправляю обычный ответ");
return [{
  json: {
    hasTavilyFormat: false,
    requiresSearch: "false",
    output: aiResponse
  }
}];

// Подготовка данных для второго AI Agent
const tavilyResults = $input.first().json;
const staticData = $getWorkflowStaticData('global');

// Находим текущее понятие
let currentConcept = "";
let currentTopic = "";

if (staticData.learningPlan && staticData.learningPlan.length > 0) {
  // Ищем неиспользованное понятие
  for (const topic of staticData.learningPlan) {
    for (const concept of topic.concepts) {
      if (!staticData.completedConcepts.includes(concept)) {
        currentConcept = concept;
        currentTopic = topic.name;
        break;
      }
    }
    if (currentConcept) break;
  }
}

return [{
  json: {
    concept: currentConcept,
    topic: currentTopic,
    originalTavilyData: tavilyResults,
    completedConcepts: staticData.completedConcepts?.length || 0,
    totalConcepts: staticData.learningPlan ? 
      staticData.learningPlan.reduce((sum, t) => sum + t.concepts.length, 0) : 0
  }
}];

// Просто передаем ответ в Telegram
const item = $input.first();

// Берем ответ AI
const response = item.json.output || "Ответ не получен";

// Получаем chatId
const chatId = item.json.chatId || "unknown";

// Убираем tavily запросы если они есть
let telegramText = response.replace(/tavily\(query="[^"]+"\)/g, '').trim();

return [{
  json: {
    TelegramText: telegramText,
    chatId: chatId
  }
}];
